    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const [callsData, callersData, calledData] = await Promise.all([
        apiCall('/api/statistics/calls'),
        apiCall('/api/statistics/top-callers?limit=5'),
        apiCall('/api/statistics/top-called?limit=5'),
